#[derive(Clone, Copy, PartialEq)]
enum LinkMode { P, H, L }
#[derive(Clone, Copy)]
enum CmpKind { Eq, Lt, Gt }
#[derive(Clone, Copy)]
struct NumCmp { kind: CmpKind, n: i64 }
impl NumCmp { fn parse(s: &str) -> Result<Self,String> { let (kind, rest) = if let Some(r)=s.strip_prefix('+') {(CmpKind::Gt,r)} else if let Some(r)=s.strip_prefix('-') {(CmpKind::Lt,r)} else {(CmpKind::Eq,s)}; let n=rest.parse::<i64>().map_err(|_| format!("invalid numeric argument `{}`",s))?; Ok(Self{kind,n}) } fn test(&self, v:i64)->bool{match self.kind{CmpKind::Eq=>v==self.n,CmpKind::Lt=>v<self.n,CmpKind::Gt=>v>self.n}} }

enum OutDest { Stdout, Stderr, File(File) }
struct ExecBatch { argv: Vec<String>, dir: bool, files: Vec<PathBuf> }
struct Config { link_mode: LinkMode, depth_first: bool, maxdepth: Option<usize>, mindepth: usize, xdev: bool, ignore_race: bool, files0_seen: bool, initial_paths: bool, paths: Vec<PathBuf>, outputs: Vec<OutDest>, batches: Vec<ExecBatch> }
impl Config { fn new(link_mode: LinkMode, paths: Vec<PathBuf>, initial_paths: bool) -> Self { Self{link_mode,depth_first:false,maxdepth:None,mindepth:0,xdev:false,ignore_race:false,files0_seen:false,initial_paths,paths,outputs:Vec::new(),batches:Vec::new()} } }
struct Runtime { exit_bad: bool, quit: bool, outputs: Vec<OutDest>, batches: Vec<ExecBatch> }
impl Runtime { fn write_out(&mut self, id: usize, bytes: &[u8]) -> io::Result<()> { match &mut self.outputs[id] { OutDest::Stdout => io::stdout().write_all(bytes), OutDest::Stderr => io::stderr().write_all(bytes), OutDest::File(f) => f.write_all(bytes) } } }

struct Info { path: PathBuf, root: PathBuf, depth: usize, meta: Metadata, lmeta: Metadata }

enum Expr { True, False, Name(String,bool), PathPat(String,bool), Regex(String,bool), Type(Vec<char>,bool), Empty, Perm(char,u32), Size(NumCmp,u64), Time(char,NumCmp), Uid(NumCmp), Gid(NumCmp), Links(NumCmp), Inum(NumCmp), User(u32), Group(u32), NoUser, NoGroup, Newer(i64,i64,char), SameFile(u64,u64), Access(i32), Print(bool), Printf(String,usize), Ls(usize), Delete, Prune, Quit, Exec(Vec<String>,bool), ExecPlus(usize), Not(Box<Expr>), And(Box<Expr>,Box<Expr>), Or(Box<Expr>,Box<Expr>), Comma(Box<Expr>,Box<Expr>) }

struct EvalCtx<'a> { info: &'a Info, rt: &'a mut Runtime, prune: bool }
impl Expr { fn eval(&self, ctx: &mut EvalCtx) -> bool { match self { Expr::True=>true, Expr::False=>false,
Expr::Name(p,ic)=>fnmatch(p,&basename(&ctx.info.path),*ic), Expr::PathPat(p,ic)=>fnmatch(p,&path_s(&ctx.info.path),*ic), Expr::Regex(p,ic)=>regex_full(p,&path_s(&ctx.info.path),*ic),
Expr::Type(v,xtype)=>{ let m=if *xtype { xtype_meta(ctx.info).unwrap_or(&ctx.info.meta) } else { &ctx.info.meta }; v.iter().any(|c| type_char(m)==*c) },
Expr::Empty=>{ if ctx.info.meta.file_type().is_file(){ctx.info.meta.len()==0} else if ctx.info.meta.file_type().is_dir(){ match fs::read_dir(&ctx.info.path){Ok(mut r)=>r.next().is_none(),Err(e)=>{eprintln!("find: '{}': {}",path_s(&ctx.info.path),e); ctx.rt.exit_bad=true; false}} } else {false} },
Expr::Perm(how,mask)=>{ let mode=ctx.info.meta.permissions().mode() & 0o7777; match how { '-'=> (mode & mask)==*mask, '/'=> *mask==0 || (mode & mask)!=0, _=> mode==*mask } },
Expr::Size(c,u)=>{ let sz=ctx.info.meta.len(); let units=if *u==1 {sz as i64} else {((sz + *u - 1)/ *u) as i64}; c.test(units) },
Expr::Time(k,c)=>{ let now=now_sec(); let t=match k{'a'=>ctx.info.meta.atime(),'c'=>ctx.info.meta.ctime(),_=>ctx.info.meta.mtime()}; let age=now-t; let val= if matches!(k,'A'|'C'|'M') { age/60 } else { age/86400 }; c.test(val) },
Expr::Uid(c)=>c.test(ctx.info.meta.uid() as i64), Expr::Gid(c)=>c.test(ctx.info.meta.gid() as i64), Expr::Links(c)=>c.test(ctx.info.meta.nlink() as i64), Expr::Inum(c)=>c.test(ctx.info.meta.ino() as i64), Expr::User(u)=>ctx.info.meta.uid()==*u, Expr::Group(g)=>ctx.info.meta.gid()==*g,
Expr::NoUser=>users::get_user_by_uid(ctx.info.meta.uid()).is_none(), Expr::NoGroup=>users::get_group_by_gid(ctx.info.meta.gid()).is_none(),
Expr::Newer(sec,nsec,which)=>{ let (s,ns)=match which{'a'=>(ctx.info.meta.atime(),ctx.info.meta.atime_nsec()),'c'=>(ctx.info.meta.ctime(),ctx.info.meta.ctime_nsec()),_=>(ctx.info.meta.mtime(),ctx.info.meta.mtime_nsec())}; s>*sec || (s==*sec && ns>*nsec) },
Expr::SameFile(d,i)=>ctx.info.meta.dev()==*d && ctx.info.meta.ino()==*i,
Expr::Access(mode)=>access(&ctx.info.path,*mode),
Expr::Print(nul)=>{ let mut b=ctx.info.path.as_os_str().as_bytes().to_vec(); b.push(if *nul {0} else {b'\n'}); let _=io::stdout().write_all(&b); true },
Expr::Printf(fmt,id)=>{ let s=render_printf(fmt,ctx.info); let _=ctx.rt.write_out(*id,s.as_bytes()); true },
Expr::Ls(id)=>{ let s=format_ls(ctx.info); let _=ctx.rt.write_out(*id,s.as_bytes()); true },
Expr::Delete=>{ let r=if ctx.info.meta.file_type().is_dir(){fs::remove_dir(&ctx.info.path)}else{fs::remove_file(&ctx.info.path)}; match r{Ok(_)=>true,Err(e)=>{ if e.kind()==io::ErrorKind::NotFound {true} else {eprintln!("find: cannot delete '{}': {}",path_s(&ctx.info.path),e); ctx.rt.exit_bad=true; false}}} },
Expr::Prune=>{ctx.prune=true; true}, Expr::Quit=>{ctx.rt.quit=true; true},
Expr::Exec(argv,dir)=>run_exec(argv,*dir,&ctx.info.path), Expr::ExecPlus(id)=>{ctx.rt.batches[*id].files.push(ctx.info.path.clone()); true},
Expr::Not(e)=>!e.eval(ctx), Expr::And(a,b)=>{ if a.eval(ctx){b.eval(ctx)}else{false} }, Expr::Or(a,b)=>{ if a.eval(ctx){true}else{b.eval(ctx)} }, Expr::Comma(a,b)=>{a.eval(ctx); b.eval(ctx)} } } }

fn path_s(p:&Path)->String{p.as_os_str().to_string_lossy().into_owned()}
fn basename(p:&Path)->String{ if p.as_os_str().as_bytes()==b"/" {"/".into()} else { p.file_name().unwrap_or_else(||p.as_os_str()).to_string_lossy().into_owned() } }
fn dirname(p:&Path)->String{ let s=path_s(p); match s.rfind('/') { None=>".".into(), Some(0)=>"".into(), Some(i)=>s[..i].into() } }
fn now_sec()->i64{SystemTime::now().duration_since(UNIX_EPOCH).unwrap().as_secs() as i64}
fn fnmatch(pat:&str, text:&str, icase:bool)->bool{ let (p,t) = if icase {(pat.to_lowercase(),text.to_lowercase())} else {(pat.to_string(),text.to_string())}; let cp=CString::new(p).unwrap(); let ct=CString::new(t).unwrap(); unsafe{libc::fnmatch(cp.as_ptr(),ct.as_ptr(),0)==0} }
fn regex_full(p:&str,t:&str,icase:bool)->bool{ RegexBuilder::new(p).case_insensitive(icase).build().map(|r| r.find(t).map(|m|m.start()==0&&m.end()==t.len()).unwrap_or(false)).unwrap_or(false) }
fn type_char(m:&Metadata)->char{let ft=m.file_type(); if ft.is_dir(){'d'}else if ft.is_file(){'f'}else if ft.is_symlink(){'l'}else if ft.is_block_device(){'b'}else if ft.is_char_device(){'c'}else if ft.is_fifo(){'p'}else if ft.is_socket(){'s'}else{'U'}}
fn xtype_meta(info:&Info)->Option<&Metadata>{ if info.lmeta.file_type().is_symlink(){ fs::metadata(&info.path).ok().as_ref(); None } else {Some(&info.meta)} }
fn access(p:&Path, mode:i32)->bool{ CString::new(p.as_os_str().as_bytes()).ok().map(|c| unsafe{libc::access(c.as_ptr(),mode)==0}).unwrap_or(false) }
fn run_exec(argv:&[String], dir:bool, path:&Path)->bool{ if argv.is_empty(){return false} let rep=if dir{format!("./{}",basename(path))}else{path_s(path)}; let mut cmd=Command::new(&argv[0]); for a in &argv[1..]{cmd.arg(a.replace("{}",&rep));} if dir { if let Some(p)=path.parent(){cmd.current_dir(if p.as_os_str().is_empty(){Path::new(".")}else{p});} } cmd.status().map(|s|s.success()).unwrap_or(false) }
fn run_batches(rt:&mut Runtime){ for b in &mut rt.batches { if b.files.is_empty(){continue} if b.argv.is_empty(){continue} let mut cmd=Command::new(&b.argv[0]); for a in &b.argv[1..]{cmd.arg(a);} for f in &b.files{cmd.arg(f);} if !cmd.status().map(|s|s.success()).unwrap_or(false){rt.exit_bad=true;} b.files.clear(); } }
fn render_printf(fmt:&str, info:&Info)->String{ let mut out=String::new(); let mut it=fmt.chars().peekable(); while let Some(c)=it.next(){ if c=='\\'{ match it.next(){Some('n')=>out.push('\n'),Some('t')=>out.push('\t'),Some('0')=>out.push('\0'),Some('r')=>out.push('\r'),Some('b')=>out.push('\x08'),Some('f')=>out.push('\x0c'),Some('v')=>out.push('\x0b'),Some('\\')=>out.push('\\'),Some(x)=>{out.push('\\');out.push(x)},None=>out.push('\\')} } else if c=='%' { if it.peek()==Some(&'%'){it.next();out.push('%');continue} let mut left=false; let mut sharp=false; while let Some(&f)=it.peek(){ if f=='-' {left=true;it.next();} else if f=='#'{sharp=true;it.next();} else if f=='0'||f=='+'{it.next();} else {break} } let mut width=0usize; while let Some(&d)=it.peek(){ if d.is_ascii_digit(){width=width*10+d.to_digit(10).unwrap() as usize;it.next();}else{break} } let d=it.next().unwrap_or('%'); let mut s=match d { 'p'=>path_s(&info.path), 'f'=>basename(&info.path), 'h'=>dirname(&info.path), 'H'=>path_s(&info.root), 'P'=>info.path.strip_prefix(&info.root).ok().map(path_s).unwrap_or_else(||path_s(&info.path)), 's'=>info.meta.len().to_string(), 'm'=>if sharp{format!("0{:o}",info.meta.permissions().mode()&0o7777)}else{format!("{:o}",info.meta.permissions().mode()&0o7777)}, 'u'=>users::get_user_by_uid(info.meta.uid()).map(|u|u.name().to_string_lossy().into_owned()).unwrap_or_else(||info.meta.uid().to_string()), 'g'=>users::get_group_by_gid(info.meta.gid()).map(|g|g.name().to_string_lossy().into_owned()).unwrap_or_else(||info.meta.gid().to_string()), 'U'=>info.meta.uid().to_string(), 'G'=>info.meta.gid().to_string(), 'i'=>info.meta.ino().to_string(), 'n'=>info.meta.nlink().to_string(), 'd'=>info.depth.to_string(), 'D'=>info.meta.dev().to_string(), 'b'=>info.meta.blocks().to_string(), 'k'=>((info.meta.blocks()+1)/2).to_string(), 'y'=>type_char(&info.meta).to_string(), 'Y'=>type_char(&info.meta).to_string(), 'l'=>if info.lmeta.file_type().is_symlink(){fs::read_link(&info.path).map(|p|path_s(&p)).unwrap_or_default()}else{String::new()}, 'M'=>mode_string(&info.meta), 'a'|'c'|'t'=>info.meta.mtime().to_string(), 'A'|'C'|'T'=>{let _=it.next(); info.meta.mtime().to_string()}, _=>d.to_string()}; if width>s.len(){let pad=" ".repeat(width-s.len()); if left{s.push_str(&pad)}else{s=format!("{}{}",pad,s)}} out.push_str(&s); } else {out.push(c)} } out }
fn mode_string(m:&Metadata)->String{ let mode=m.permissions().mode(); let mut s=String::new(); s.push(type_char(m)); for (r,w,x) in [(0o400,0o200,0o100),(0o040,0o020,0o010),(0o004,0o002,0o001)]{s.push(if mode&r!=0{'r'}else{'-'});s.push(if mode&w!=0{'w'}else{'-'});s.push(if mode&x!=0{'x'}else{'-'});} s }
fn format_ls(info:&Info)->String{format!("{:>8} {:>4} {} {:>3} {:>5} {:>5} {:>8} {}\n",info.meta.ino(),(info.meta.blocks()+1)/2,mode_string(&info.meta),info.meta.nlink(),info.meta.uid(),info.meta.gid(),info.meta.len(),path_s(&info.path))}

fn parse_perm(s:&str)->Result<(char,u32),String>{ let (how,body)=if let Some(r)=s.strip_prefix('-'){('-',r)}else if let Some(r)=s.strip_prefix('/') {('/',r)} else {('=',s)}; if let Ok(v)=u32::from_str_radix(body,8){return Ok((how,v))} let mut mask=0u32; for cl in body.split(','){ let mut who=0u32; let mut chars=cl.chars().peekable(); while let Some(&c)=chars.peek(){match c{'u'=>{who|=0o700;chars.next();},'g'=>{who|=0o070;chars.next();},'o'=>{who|=0o007;chars.next();},'a'=>{who|=0o777;chars.next();},_=>break}} if who==0{who=0o777} if matches!(chars.peek(),Some('+')|Some('=')|Some('-')){chars.next();} for c in chars{match c{'r'=>mask|=who&0o444,'w'=>mask|=who&0o222,'x'=>mask|=who&0o111,'s'=>{if who&0o700!=0{mask|=0o4000} if who&0o070!=0{mask|=0o2000}},'t'=>mask|=0o1000,_=>{}}} } Ok((how,mask)) }
fn size_arg(s:&str)->Result<(NumCmp,u64),String>{ let (num,suf)=if s.chars().last().map(|c|c.is_ascii_alphabetic()).unwrap_or(false){(&s[..s.len()-1],s.chars().last().unwrap())}else{(s,'b')}; let u=match suf{'c'=>1,'w'=>2,'b'=>512,'k'=>1024,'M'=>1024*1024,'G'=>1024*1024*1024,_=>512}; Ok((NumCmp::parse(num)?,u)) }
fn ref_meta(p:&str, lm:LinkMode)->Result<Metadata,String>{ if lm==LinkMode::P { fs::symlink_metadata(p).map_err(|e|format!("{}: {}",p,e)) } else { fs::metadata(p).or_else(|_|fs::symlink_metadata(p)).map_err(|e|format!("{}: {}",p,e)) } }

struct Parser { toks: Vec<String>, pos: usize, cfg: Config, has_action: bool }
impl Parser { fn peek(&self)->Option<&str>{self.toks.get(self.pos).map(|s|s.as_str())} fn next(&mut self)->Option<String>{let r=self.toks.get(self.pos).cloned(); if r.is_some(){self.pos+=1} r} fn need(&mut self, what:&str)->Result<String,String>{self.next().ok_or_else(||format!("missing argument to {}",what))}
fn parse(mut self)->Result<(Expr,Config,bool),String>{ let e=if self.toks.is_empty(){Expr::True}else{self.parse_comma()?}; if self.pos!=self.toks.len(){return Err(format!("unknown predicate `{}`",self.toks[self.pos]))} Ok((e,self.cfg,self.has_action)) }
fn parse_comma(&mut self)->Result<Expr,String>{ let mut e=self.parse_or()?; while self.peek()==Some(","){self.next(); let r=self.parse_or()?; e=Expr::Comma(Box::new(e),Box::new(r));} Ok(e)}
fn parse_or(&mut self)->Result<Expr,String>{ let mut e=self.parse_and()?; while matches!(self.peek(),Some("-o")|Some("-or")){self.next(); let r=self.parse_and()?; e=Expr::Or(Box::new(e),Box::new(r));} Ok(e)}
fn parse_and(&mut self)->Result<Expr,String>{ let mut e=self.parse_not()?; loop { match self.peek(){Some(")")|None|Some("-o")|Some("-or")|Some(",")=>break,Some("-a")|Some("-and")=>{self.next(); let r=self.parse_not()?; e=Expr::And(Box::new(e),Box::new(r));},_=>{let r=self.parse_not()?; e=Expr::And(Box::new(e),Box::new(r));}} } Ok(e)}
fn parse_not(&mut self)->Result<Expr,String>{ if matches!(self.peek(),Some("!")|Some("-not")){self.next(); Ok(Expr::Not(Box::new(self.parse_not()?)))} else {self.primary()} }
fn primary(&mut self)->Result<Expr,String>{ let t=self.need("expression")?; match t.as_str(){"("=>{let e=self.parse_comma()?; if self.next().as_deref()!=Some(")"){return Err("missing `)'".into())} Ok(e)}, "-true"=>Ok(Expr::True), "-false"=>Ok(Expr::False), "-name"=>Ok(Expr::Name(self.need("-name")?,false)), "-iname"=>Ok(Expr::Name(self.need("-iname")?,true)), "-path"|"-wholename"=>Ok(Expr::PathPat(self.need("-path")?,false)), "-ipath"|"-iwholename"=>Ok(Expr::PathPat(self.need("-ipath")?,true)), "-regex"=>Ok(Expr::Regex(self.need("-regex")?,false)), "-iregex"=>Ok(Expr::Regex(self.need("-iregex")?,true)), "-type"=>Ok(Expr::Type(self.need("-type")?.split(',').filter_map(|s|s.chars().next()).collect(),false)), "-xtype"=>Ok(Expr::Type(self.need("-xtype")?.split(',').filter_map(|s|s.chars().next()).collect(),true)), "-empty"=>Ok(Expr::Empty), "-perm"=>{let (h,m)=parse_perm(&self.need("-perm")?)?; Ok(Expr::Perm(h,m))}, "-size"=>{let (c,u)=size_arg(&self.need("-size")?)?; Ok(Expr::Size(c,u))}, "-mtime"=>Ok(Expr::Time('m',NumCmp::parse(&self.need("-mtime")?)?)), "-atime"=>Ok(Expr::Time('a',NumCmp::parse(&self.need("-atime")?)?)), "-ctime"=>Ok(Expr::Time('c',NumCmp::parse(&self.need("-ctime")?)?)), "-mmin"=>Ok(Expr::Time('M',NumCmp::parse(&self.need("-mmin")?)?)), "-amin"=>Ok(Expr::Time('A',NumCmp::parse(&self.need("-amin")?)?)), "-cmin"=>Ok(Expr::Time('C',NumCmp::parse(&self.need("-cmin")?)?)), "-uid"=>Ok(Expr::Uid(NumCmp::parse(&self.need("-uid")?)?)), "-gid"=>Ok(Expr::Gid(NumCmp::parse(&self.need("-gid")?)?)), "-inum"=>Ok(Expr::Inum(NumCmp::parse(&self.need("-inum")?)?)), "-links"=>Ok(Expr::Links(NumCmp::parse(&self.need("-links")?)?)), "-user"=>{let s=self.need("-user")?; let u=s.parse().ok().or_else(||users::get_user_by_name(OsStr::new(&s)).map(|u|u.uid())).ok_or_else(||format!("unknown user {}",s))?; Ok(Expr::User(u))}, "-group"=>{let s=self.need("-group")?; let g=s.parse().ok().or_else(||users::get_group_by_name(OsStr::new(&s)).map(|g|g.gid())).ok_or_else(||format!("unknown group {}",s))?; Ok(Expr::Group(g))}, "-nouser"=>Ok(Expr::NoUser), "-nogroup"=>Ok(Expr::NoGroup), "-newer"=>{let m=ref_meta(&self.need("-newer")?,self.cfg.link_mode)?; Ok(Expr::Newer(m.mtime(),m.mtime_nsec(),'m'))}, "-anewer"=>{let m=ref_meta(&self.need("-anewer")?,self.cfg.link_mode)?; Ok(Expr::Newer(m.mtime(),m.mtime_nsec(),'a'))}, "-cnewer"=>{let m=ref_meta(&self.need("-cnewer")?,self.cfg.link_mode)?; Ok(Expr::Newer(m.mtime(),m.mtime_nsec(),'c'))}, "-samefile"=>{let m=ref_meta(&self.need("-samefile")?,self.cfg.link_mode)?; Ok(Expr::SameFile(m.dev(),m.ino()))}, "-readable"=>Ok(Expr::Access(libc::R_OK)), "-writable"=>Ok(Expr::Access(libc::W_OK)), "-executable"=>Ok(Expr::Access(libc::X_OK)), "-print"=>{self.has_action=true; Ok(Expr::Print(false))}, "-print0"=>{self.has_action=true; Ok(Expr::Print(true))}, "-printf"=>{self.has_action=true; Ok(Expr::Printf(self.need("-printf")?,0))}, "-fprintf"=>{self.has_action=true; let id=self.add_output(&self.need("-fprintf file")?)?; Ok(Expr::Printf(self.need("-fprintf format")?,id))}, "-fprint"=>{self.has_action=true; let id=self.add_output(&self.need("-fprint")?)?; Ok(Expr::Printf("%p\\n".into(),id))}, "-fprint0"=>{self.has_action=true; let id=self.add_output(&self.need("-fprint0")?)?; Ok(Expr::Printf("%p\\0".into(),id))}, "-ls"=>{self.has_action=true; Ok(Expr::Ls(0))}, "-fls"=>{self.has_action=true; let id=self.add_output(&self.need("-fls")?)?; Ok(Expr::Ls(id))}, "-delete"=>{self.has_action=true; self.cfg.depth_first=true; Ok(Expr::Delete)}, "-prune"=>Ok(Expr::Prune), "-quit"=>Ok(Expr::Quit), "-exec"|"-execdir"=>self.parse_exec(t=="-execdir"), "-ok"|"-okdir"=>self.parse_exec(t=="-okdir"), "-maxdepth"=>{self.cfg.maxdepth=Some(self.need("-maxdepth")?.parse().map_err(|_|"invalid -maxdepth".to_string())?); Ok(Expr::True)}, "-mindepth"=>{self.cfg.mindepth=self.need("-mindepth")?.parse().map_err(|_|"invalid -mindepth".to_string())?; Ok(Expr::True)}, "-depth"|"-d"=>{self.cfg.depth_first=true; Ok(Expr::True)}, "-xdev"|"-mount"=>{self.cfg.xdev=true; Ok(Expr::True)}, "-ignore_readdir_race"=>{self.cfg.ignore_race=true; Ok(Expr::True)}, "-noignore_readdir_race"=>{self.cfg.ignore_race=false; Ok(Expr::True)}, "-follow"=>{self.cfg.link_mode=LinkMode::L; Ok(Expr::True)}, "-noleaf"|"-daystart"|"-warn"|"-nowarn"=>Ok(Expr::True), "-regextype"=>{let _=self.need("-regextype")?; Ok(Expr::True)}, "-files0-from"=>{let f=self.need("-files0-from")?; self.read_files0(&f)?; Ok(Expr::True)}, "-help"|"--help"=>{print_help(); std::process::exit(0)}, "-version"|"--version"=>{println!("find (rust) 1.0"); std::process::exit(0)}, _=>Err(format!("unknown predicate `{}`",t)) } }
fn add_output(&mut self,p:&str)->Result<usize,String>{ let id=self.cfg.outputs.len(); let o=match p{"/dev/stdout"=>OutDest::Stdout,"/dev/stderr"=>OutDest::Stderr,_=>OutDest::File(File::create(p).map_err(|e|format!("{}: {}",p,e))?)}; self.cfg.outputs.push(o); Ok(id)}
fn read_files0(&mut self,p:&str)->Result<(),String>{ if self.cfg.initial_paths{return Err("-files0-from is incompatible with command-line paths".into())} self.cfg.files0_seen=true; let mut data=Vec::new(); if p=="-"{io::stdin().read_to_end(&mut data).map_err(|e|e.to_string())?}else{File::open(p).and_then(|mut f|f.read_to_end(&mut data)).map_err(|e|format!("{}: {}",p,e))?; } self.cfg.paths.clear(); if data.is_empty(){return Ok(())} let parts:Vec<&[u8]>=data.split(|b|*b==0).collect(); for (i,part) in parts.iter().enumerate(){ if part.is_empty(){ if i==parts.len()-1 {continue} return Err("invalid zero-length file name in input file".into()) } self.cfg.paths.push(PathBuf::from(OsStr::from_bytes(part))); } Ok(()) }
fn parse_exec(&mut self,dir:bool)->Result<Expr,String>{ self.has_action=true; let mut argv=Vec::new(); loop{let a=self.need("-exec")?; if a==";"{return Ok(Expr::Exec(argv,dir))} if a=="+"{ if argv.last().map(|s|s.as_str())!=Some("{}"){return Err("-exec ... + requires {} before +".into())} argv.pop(); let id=self.cfg.batches.len(); self.cfg.batches.push(ExecBatch{argv,dir,files:Vec::new()}); return Ok(Expr::ExecPlus(id)) } argv.push(a); } }
}

fn visit(path:PathBuf, root:&Path, depth:usize, root_dev:u64, cfg:&Config, rt:&mut Runtime, expr:&Expr, default_print:bool, is_root:bool){ if rt.quit{return} let lmeta=match fs::symlink_metadata(&path){Ok(m)=>m,Err(e)=>{if !cfg.ignore_race{eprintln!("find: '{}': {}",path_s(&path),e);rt.exit_bad=true;} return}}; let follow=cfg.link_mode==LinkMode::L || (cfg.link_mode==LinkMode::H && is_root); let meta=if follow{fs::metadata(&path).unwrap_or_else(|_|lmeta.clone())}else{lmeta.clone()}; let info=Info{path:path.clone(),root:root.to_path_buf(),depth,meta,lmeta}; if cfg.depth_first { descend(&info,root_dev,cfg,rt,expr,default_print); evaluate(&info,cfg,rt,expr,default_print,false); } else { let pr=evaluate(&info,cfg,rt,expr,default_print,true); if !pr { descend(&info,root_dev,cfg,rt,expr,default_print); } } }
fn evaluate(info:&Info,cfg:&Config,rt:&mut Runtime,expr:&Expr,default_print:bool,allow_prune:bool)->bool{ if rt.quit{return false} if info.depth<cfg.mindepth{return false} let mut ctx=EvalCtx{info,rt,prune:false}; let ok=expr.eval(&mut ctx); if !allow_prune || cfg.depth_first{ctx.prune=false} if ok && default_print && !ctx.rt.quit { let mut b=info.path.as_os_str().as_bytes().to_vec(); b.push(b'\n'); let _=io::stdout().write_all(&b); } ctx.prune }
fn descend(info:&Info, root_dev:u64, cfg:&Config, rt:&mut Runtime, expr:&Expr, default_print:bool){ if rt.quit{return} if !info.meta.file_type().is_dir(){return} if cfg.maxdepth.map(|m|info.depth>=m).unwrap_or(false){return} if cfg.xdev && info.depth>0 && info.meta.dev()!=root_dev{return} let rd=match fs::read_dir(&info.path){Ok(r)=>r,Err(e)=>{eprintln!("find: '{}': {}",path_s(&info.path),e);rt.exit_bad=true;return}}; for ent in rd{ if rt.quit{break} match ent{Ok(e)=>visit(e.path(),&info.root,info.depth+1,root_dev,cfg,rt,expr,default_print,false),Err(e)=>{eprintln!("find: '{}': {}",path_s(&info.path),e);rt.exit_bad=true;}} } }
fn print_help(){println!("Usage: find [-H] [-L] [-P] [path...] [expression]\nCommon primaries: -name -type -print -print0 -exec -delete -maxdepth -mindepth");}

fn main(){ let args:Vec<String>=std::env::args().collect(); let mut lm=LinkMode::P; let mut i=1; while i<args.len(){ match args[i].as_str(){"-H"=>{lm=LinkMode::H;i+=1},"-L"=>{lm=LinkMode::L;i+=1},"-P"=>{lm=LinkMode::P;i+=1},"-D"=>{ if args.get(i+1).map(|s|s=="help").unwrap_or(false){println!("Valid arguments for -D: exec,opt,rates,search,stat,tree,all,help");return} i+=2},x if x.starts_with("-O")=>{i+=1},"--help"=>{print_help();return},"--version"=>{println!("find (rust) 1.0");return},_=>break} }
 let rest=&args[i..]; let mut split=0; while split<rest.len(){let a=&rest[split]; if a.starts_with('-')||a=="("||a=="!"{break} split+=1;} let paths:Vec<PathBuf>=rest[..split].iter().map(PathBuf::from).collect(); let expr_toks=rest[split..].to_vec(); let initial_paths=!paths.is_empty(); let mut cfg=Config::new(lm,paths,initial_paths); cfg.outputs.push(OutDest::Stdout); let parser=Parser{toks:expr_toks,pos:0,cfg,has_action:false}; let (expr,mut cfg,has_action)=match parser.parse(){Ok(v)=>v,Err(e)=>{eprintln!("find: {}",e);std::process::exit(1)}}; if cfg.paths.is_empty() && !cfg.files0_seen { cfg.paths.push(PathBuf::from(".")); } let default_print=!has_action; let outputs=std::mem::take(&mut cfg.outputs); let batches=std::mem::take(&mut cfg.batches); let mut rt=Runtime{exit_bad:false,quit:false,outputs,batches}; let roots=cfg.paths.clone(); for root in roots{ if rt.quit{break} let rm=if cfg.link_mode==LinkMode::P{fs::symlink_metadata(&root)}else{fs::metadata(&root).or_else(|_|fs::symlink_metadata(&root))}; match rm{Ok(m)=>visit(root.clone(),&root,0,m.dev(),&cfg,&mut rt,&expr,default_print,true),Err(e)=>{if !cfg.ignore_race{eprintln!("find: '{}': {}",path_s(&root),e);rt.exit_bad=true;}} } } run_batches(&mut rt); std::process::exit(if rt.exit_bad{1}else{0}); }
